const DISPLAY_POSITION_EPSILON = 0.000001;
const runtimeFailurePhaseLoadSource = 1;
const runtimeFailurePhaseBuildMip = 2;
const runtimeFailurePhaseTransferMip = 3;
const runtimeFailureReasonTimeout = 2;
const runtimeFailureScopeService = 1;
export const FILTER_MODE_OFF = 0;
export const FILTER_MODE_LOWPASS = 1;
export const FILTER_MODE_HIGHPASS = 2;
export const FILTER_MODE_BANDPASS = 3;
export const FILTER_MODE_NOTCH = 4;
export const FILTER_MODE_PEAK = 5;
export const WARP_MODE_OFF = 0;
export const WARP_MODE_BEND = 1;
export const WARP_MODE_PWM = 2;
export const WARP_MODE_ASYM = 3;
export const WARP_MODE_MIRROR = 4;
export const UNISON_MAX_VOICES = 8;
export const UNISON_PHASE_MODE_CONTIGUOUS = 0;
export const UNISON_PHASE_MODE_RESET = 1;
export const UNISON_DETUNE_MODE_LINEAR = 0;
export const UNISON_DETUNE_MODE_SUPER = 1;
export const UNISON_DETUNE_MODE_EXP = 2;
export const UNISON_DETUNE_MODE_INV = 3;
export const UNISON_DETUNE_MODE_RANDOM = 4;
export const UNISON_STACK_MODE_OFF = 0;
export const UNISON_STACK_MODE_OCTAVES = 1;
export const UNISON_STACK_MODE_OCTAVES_FIFTHS = 2;
export const UNISON_STACK_MODE_CENTER_OCTAVE = 3;
export const UNISON_STACK_MODE_CENTER_TWO_OCTAVES = 4;
const FILTER_CUTOFF_MIN_HZ = 20;
const FILTER_CUTOFF_MAX_HZ = 20_000;
const FILTER_Q_MIN = 0.1;
const FILTER_Q_MAX = 20;

export type EffectiveWavetablePositionState = {
    voiceGeneration: number;
    position: number;
};

export type EffectiveFilterState = {
    voiceGeneration: number;
    hasActive: boolean;
    mode: number;
    cutoffHz: number;
    q: number;
};

export type EffectiveWarpState = {
    voiceGeneration: number;
    hasActive: boolean;
    mode: number;
    amount: number;
};

export type EffectiveUnisonState = {
    voiceGeneration: number;
    hasActive: boolean;
    voices: number;
    detune: number;
    blend: number;
    width: number;
    detuneMode: number;
    stackMode: number;
    wavetablePositionSpread: number;
    warpSpread: number;
};

export type NormalizedRuntimeTableState = {
    desiredTableIndex: number;
    desiredIntentSerial: number;
    serviceState: number;
    hasActive: boolean;
    activeTableIndex: number;
    activeGeneration: number;
    hasLoading: boolean;
    loadingTableIndex: number;
    loadingGeneration: number;
    hasFailure: boolean;
    failedTableIndex: number;
    failedGeneration: number;
    failureScope: number;
    failurePhase: number;
    failureReasonCode: number;
};

export type RuntimeTablePresentation = {
    desiredTableIndex: number;
    presentedTableIndex: number;
    activeTableIndex: number | null;
    activeGeneration: number | null;
    loadingTableIndex: number | null;
    loadingGeneration: number | null;
    isPendingSelection: boolean;
    isRetryableFailure: boolean;
    failureMessage: string | null;
};

function clamp(value: number, min: number, max: number) {
    return Math.min(Math.max(value, min), max);
}

function clampFilterCutoffHz(value: unknown) {
    return clamp(Number(value) || 0, FILTER_CUTOFF_MIN_HZ, FILTER_CUTOFF_MAX_HZ);
}

function clampFilterQ(value: unknown) {
    return clamp(Number(value) || 0, FILTER_Q_MIN, FILTER_Q_MAX);
}

function clampFilterMode(value: unknown) {
    return clamp(Math.round(Number(value) || 0), FILTER_MODE_OFF, FILTER_MODE_PEAK);
}

function clampWarpMode(value: unknown) {
    return clamp(Math.round(Number(value) || 0), WARP_MODE_OFF, WARP_MODE_MIRROR);
}

function clampWarpAmount(value: unknown) {
    return clamp(Number(value) || 0, 0, 1);
}

export function clampUnisonVoiceCount(value: unknown) {
    return clamp(Math.round(Number(value) || 1), 1, UNISON_MAX_VOICES);
}

export function clampUnison01(value: unknown) {
    return clamp(Number(value) || 0, 0, 1);
}

export function clampUnisonPhaseMode(value: unknown) {
    return clamp(Math.round(Number(value) || 0), UNISON_PHASE_MODE_CONTIGUOUS, UNISON_PHASE_MODE_RESET);
}

export function clampUnisonDetuneMode(value: unknown) {
    return clamp(Math.round(Number(value) || 0), UNISON_DETUNE_MODE_LINEAR, UNISON_DETUNE_MODE_RANDOM);
}

export function clampUnisonStackMode(value: unknown) {
    return clamp(Math.round(Number(value) || 0), UNISON_STACK_MODE_OFF, UNISON_STACK_MODE_CENTER_TWO_OCTAVES);
}

export function clampDisplayPosition(value: unknown) {
    return clamp(Number(value) || 0, 0, 1);
}

export function displayPositionsMatch(left: unknown, right: unknown, epsilon = DISPLAY_POSITION_EPSILON) {
    return Math.abs(clampDisplayPosition(left) - clampDisplayPosition(right)) <= epsilon;
}

export function mapDisplayDragToPosition(
    startValue: unknown,
    startClientY: unknown,
    nextClientY: unknown,
    dragSpan: unknown,
) {
    const safeSpan = Math.max(1, Number(dragSpan) || 0);
    const delta = (Number(startClientY) || 0) - (Number(nextClientY) || 0);

    return clampDisplayPosition((Number(startValue) || 0) + (delta / safeSpan));
}

export function normalizeEffectiveWavetablePositionMessage(message: unknown): EffectiveWavetablePositionState | null {
    const payload = (message as { event?: unknown } | null | undefined)?.event ?? message;

    if (payload === null || payload === undefined) {
        return null;
    }

    if (typeof payload === "number") {
        return {
            voiceGeneration: 0,
            position: clampDisplayPosition(payload),
        };
    }

    const rawPosition = Number((payload as { position?: unknown }).position);
    if (!Number.isFinite(rawPosition)) {
        return null;
    }

    const rawGeneration = Number((payload as { voiceGeneration?: unknown }).voiceGeneration);
    return {
        voiceGeneration: Number.isFinite(rawGeneration)
            ? Math.max(0, Math.trunc(rawGeneration))
            : 0,
        position: clampDisplayPosition(rawPosition),
    };
}

export function selectObservedWavetablePositionState(
    currentState: EffectiveWavetablePositionState | null | undefined,
    message: unknown,
) {
    const previousState = currentState && typeof currentState === "object"
        ? {
            voiceGeneration: Number.isFinite(Number(currentState.voiceGeneration))
                ? Math.trunc(Number(currentState.voiceGeneration))
                : -1,
            position: clampDisplayPosition(currentState.position),
        }
        : {
            voiceGeneration: -1,
            position: 0,
        };
    const nextState = normalizeEffectiveWavetablePositionMessage(message);

    if (!nextState) {
        return previousState;
    }

    if (nextState.voiceGeneration < previousState.voiceGeneration) {
        return previousState;
    }

    return nextState;
}

export function normalizeEffectiveFilterStateMessage(message: unknown): EffectiveFilterState | null {
    const payload = (message as { event?: unknown } | null | undefined)?.event ?? message;

    if (!payload || typeof payload !== "object") {
        return null;
    }

    const rawCutoff = Number((payload as { cutoffHz?: unknown }).cutoffHz);
    const rawQ = Number((payload as { q?: unknown }).q);

    if (!Number.isFinite(rawCutoff) || !Number.isFinite(rawQ)) {
        return null;
    }

    const rawGeneration = Number((payload as { voiceGeneration?: unknown }).voiceGeneration);
    const rawHasActive = (payload as { hasActive?: unknown }).hasActive;
    return {
        voiceGeneration: Number.isFinite(rawGeneration)
            ? Math.max(0, Math.trunc(rawGeneration))
            : 0,
        hasActive: Boolean(rawHasActive),
        mode: clampFilterMode((payload as { mode?: unknown }).mode),
        cutoffHz: clampFilterCutoffHz(rawCutoff),
        q: clampFilterQ(rawQ),
    };
}

export function selectObservedEffectiveFilterState(
    currentState: EffectiveFilterState | null | undefined,
    message: unknown,
) {
    const previousState = currentState && typeof currentState === "object"
        ? {
            voiceGeneration: Number.isFinite(Number(currentState.voiceGeneration))
                ? Math.trunc(Number(currentState.voiceGeneration))
                : -1,
            hasActive: Boolean(currentState.hasActive),
            mode: clampFilterMode(currentState.mode),
            cutoffHz: clampFilterCutoffHz(currentState.cutoffHz),
            q: clampFilterQ(currentState.q),
        }
        : {
            voiceGeneration: -1,
            hasActive: false,
            mode: FILTER_MODE_OFF,
            cutoffHz: FILTER_CUTOFF_MIN_HZ,
            q: 0.707107,
        };
    const nextState = normalizeEffectiveFilterStateMessage(message);

    if (!nextState) {
        return previousState;
    }

    if (nextState.voiceGeneration < previousState.voiceGeneration) {
        return previousState;
    }

    return nextState;
}

